@@ -126,6 +131,17 @@ func equalIntPtr(a, b *int) bool {
 	return *a == *b
 }

+// equalStringPtr compares two *string pointers for equality
+func equalStringPtr(a, b *string) bool {
+	if a == nil && b == nil {
+		return true
+	}
+	if a == nil || b == nil {
+		return false
+	}
+	return *a == *b
+}
